from langgraph.graph import StateGraph, END
from langchain_anthropic import ChatAnthropic
from typing import TypedDict, Annotated, Optional
import operator, json

class OrchestratorState(TypedDict):
    user_goal: str
    subtasks: list[str]              # planned by orchestrator
    results: Annotated[list[str], operator.add]
    next_worker: Optional[str]       # set by orchestrator each turn
    final_output: str

llm = ChatAnthropic(model="claude-sonnet-5")

def orchestrator_node(state: OrchestratorState) -> dict:
    """Plan subtasks and pick the first worker to call."""
    if not state.get("subtasks"):
        # First call: decompose goal into subtasks
        response = llm.invoke([
            {"role": "system", "content": (
                "Decompose the user goal into an ordered list of subtasks. "
                "Reply with JSON: {"subtasks": ["...", "..."]}"
            )},
            {"role": "user", "content": state["user_goal"]},
        ])
        data = json.loads(response.content)
        return {"subtasks": data["subtasks"], "next_worker": "retriever"}

    # Check if all subtasks are done
    if len(state["results"]) >= len(state["subtasks"]):
        return {"next_worker": "merger"}

    # Pick next worker based on remaining subtask
    idx = len(state["results"])
    subtask = state["subtasks"][idx]
    # Route by keyword (in production, use a classifier)
    if "retriev" in subtask.lower() or "search" in subtask.lower():
        return {"next_worker": "retriever"}
    elif "writ" in subtask.lower() or "draft" in subtask.lower():
        return {"next_worker": "writer"}
    else:
        return {"next_worker": "retriever"}

def retriever_node(state: OrchestratorState) -> dict:
    idx = len(state["results"])
    task = state["subtasks"][idx]
    response = llm.invoke([
        {"role": "system", "content": "Retrieve key facts relevant to the task."},
        {"role": "user", "content": task},
    ])
    return {"results": [response.content]}

def writer_node(state: OrchestratorState) -> dict:
    idx = len(state["results"])
    task = state["subtasks"][idx]
    context = "\n".join(state["results"])
    response = llm.invoke([
        {"role": "system", "content": "Write a concise section based on the context."},
        {"role": "user", "content": f"Task: {task}\nContext: {context}"},
    ])
    return {"results": [response.content]}

def merger_node(state: OrchestratorState) -> dict:
    all_results = "\n\n".join(state["results"])
    response = llm.invoke([
        {"role": "system", "content": "Merge the section results into a coherent final output."},
        {"role": "user", "content": all_results},
    ])
    return {"final_output": response.content}

def route_worker(state: OrchestratorState) -> str:
    return state.get("next_worker", "merger")

graph = StateGraph(OrchestratorState)
graph.add_node("orchestrator", orchestrator_node)
graph.add_node("retriever", retriever_node)
graph.add_node("writer", writer_node)
graph.add_node("merger", merger_node)

graph.set_entry_point("orchestrator")
graph.add_conditional_edges("orchestrator", route_worker, {
    "retriever": "retriever",
    "writer": "writer",
    "merger": "merger",
})
graph.add_edge("retriever", "orchestrator")
graph.add_edge("writer", "orchestrator")
graph.add_edge("merger", END)

app = graph.compile()
